if(c<128){ts[t][0]=c;tl[t]=1;}else if(c<2048){ts[t][0]=0xC0|(c>>6);ts[t][1]=0x80|(c&63);tl[t]=2;}
else{ts[t][0]=0xE0|(c>>12);ts[t][1]=0x80|((c>>6)&63);ts[t][2]=0x80|(c&63);tl[t]=3;}ti(t);}
FILE*f=fopen(p,"r");char ln[256];fgets(ln,256,f);int x=0;
while(fgets(ln,256,f)&&x<NM){int l=strlen(ln);if(ln[l-1]=='\n')ln[--l]=0;int sp=-1;
for(int i=0;i<l;i++)if(ln[i]==' '){sp=i;break;}if(sp<0)continue;
int li=tf(ln,sp),ri=tf(ln+sp+1,l-sp-1);if(li<0||ri<0)continue;
ml[x]=li;mr[x]=ri;int a=tl[li];memcpy(ts[256+x],ts[li],a);
memcpy(ts[256+x]+a,ts[ri],tl[ri]);tl[256+x]=a+tl[ri];
memcpy(rb[256+x],rb[li],rl[li]);memcpy(rb[256+x]+rl[li],rb[ri],rl[ri]);
rl[256+x]=rl[li]+rl[ri];ti(256+x);mi(x);x++;}fclose(f);}
int tokenize(char*t,int*o){int n=strlen(t);for(int i=0;i<n;i++)o[i]=bt[(unsigned char)t[i]];
while(1){int bs=NM,bp=-1;for(int i=0;i<n-1;i++){int r=mf(o[i],o[i+1]);if(r>=0&&r<bs){bs=r;bp=i;}}
if(bp<0)break;o[bp]=256+bs;memmove(o+bp+1,o+bp+2,(n-bp-2)*sizeof(int));n--;}return n;}
float sc[1024];
float G(float x){return.5f*x*(1+tanhf(.7978845608f*(x+.044715f*x*x*x)));}
float lo[2];
void run(int gm){
float*x=calloc(1024*C,sizeof(float)),*xn=malloc(1024*C*sizeof(float)),
*q=malloc(1024*C*sizeof(float)),*k=malloc(1024*C*sizeof(float)),
*v=malloc(1024*C*sizeof(float)),*ao=malloc(1024*C*sizeof(float)),
*ff=malloc(1024*F*sizeof(float));
float gm1=gm?1.0f:0.0f;
int T=nt;for(int t=0;t<T;t++)for(int i=0;i<C;i++)x[t*C+i]=wte[tk[t]*C+i]+wpe[t*C+i];
float*p=W+39383808;
for(int l=0;l<12;l++){
float*g1=p;p+=C;float*b1=p;p+=C;
float*qw=p;p+=C*C;float*kw=p;p+=C*C;float*vw=p;p+=C*C;float*ow=p;p+=C*C;
float*qb=p;p+=C;float*kb=p;p+=C;float*vb=p;p+=C;float*ob_=p;p+=C;
float*g2=p;p+=C;float*b2=p;p+=C;
float*fw=p;p+=C*F;float*fb_=p;p+=F;
float*pw=p;p+=F*C;float*pb_=p;p+=C;
for(int t=0;t<T;t++){float m=0,vv=0;
for(int i=0;i<C;i++)m+=x[t*C+i];m/=C;
for(int i=0;i<C;i++)vv+=(x[t*C+i]-m)*(x[t*C+i]-m);vv=sqrtf(vv/C+1e-5f);
for(int i=0;i<C;i++)xn[t*C+i]=(x[t*C+i]-m)/vv*(g1[i]+gm1)+b1[i];}
for(int t=0;t<T;t++)for(int j=0;j<C;j++){float sq=qb[j],sk=kb[j],sv=vb[j];
for(int i=0;i<C;i++){sq+=xn[t*C+i]*qw[j*C+i];sk+=xn[t*C+i]*kw[j*C+i];sv+=xn[t*C+i]*vw[j*C+i];}
q[t*C+j]=sq;k[t*C+j]=sk;v[t*C+j]=sv;}
for(int h=0;h<H;h++)for(int t=0;t<T;t++){
for(int s=0;s<=t;s++){float d=0;for(int i=0;i<D;i++)d+=q[t*C+h*D+i]*k[s*C+h*D+i];sc[s]=d/sqrtf(D);}
float mx=-1e30f;for(int s=0;s<=t;s++)if(sc[s]>mx)mx=sc[s];
float ss=0;for(int s=0;s<=t;s++){sc[s]=expf(sc[s]-mx);ss+=sc[s];}
for(int s=0;s<=t;s++)sc[s]/=ss;
for(int i=0;i<D;i++){float vv=0;for(int s=0;s<=t;s++)vv+=sc[s]*v[s*C+h*D+i];ao[t*C+h*D+i]=vv;}}
for(int t=0;t<T;t++)for(int j=0;j<C;j++){float s=ob_[j];
for(int i=0;i<C;i++)s+=ao[t*C+i]*ow[j*C+i];x[t*C+j]+=s;}
for(int t=0;t<T;t++){float m=0,vv=0;
for(int i=0;i<C;i++)m+=x[t*C+i];m/=C;
for(int i=0;i<C;i++)vv+=(x[t*C+i]-m)*(x[t*C+i]-m);vv=sqrtf(vv/C+1e-5f);
for(int i=0;i<C;i++)xn[t*C+i]=(x[t*C+i]-m)/vv*(g2[i]+gm1)+b2[i];}
for(int t=0;t<T;t++)for(int j=0;j<F;j++){float s=fb_[j];
for(int i=0;i<C;i++)s+=xn[t*C+i]*fw[j*C+i];ff[t*F+j]=G(s);}
for(int t=0;t<T;t++)for(int j=0;j<C;j++){float s=pb_[j];
for(int i=0;i<F;i++)s+=ff[t*F+i]*pw[j*F+i];x[t*C+j]+=s;}}
float*g=p;p+=C;float*b=p;
for(int t=0;t<T;t++){float m=0,vv=0;
for(int i=0;i<C;i++)m+=x[t*C+i];m/=C;
for(int i=0;i<C;i++)vv+=(x[t*C+i]-m)*(x[t*C+i]-m);vv=sqrtf(vv/C+1e-5f);
for(int i=0;i<C;i++)xn[t*C+i]=(x[t*C+i]-m)/vv*(g[i]+gm1)+b[i];}
int lt=T-1,best=0;float bv=-1e30f;
for(int j=0;j<V;j++){float s=0;for(int i=0;i<C;i++)s+=xn[lt*C+i]*wte[j*C+i];if(s>bv){bv=s;best=j;}}
lo[0]=bv;lo[1]=best;
free(x);free(xn);free(q);free(k);free(v);free(ao);free(ff);}
int main(int argc,char**argv){
FILE*f=fopen(argv[1],"rb");fseek(f,0,SEEK_END);long sz=ftell(f);fseek(f,0,SEEK_SET);
W=malloc(sz);fread(W,1,sz,f);fclose(f);
wte=W;wpe=wte+V*C;
lb(argv[2]);nt=tokenize(argv[3],tk);
for(int gm=0;gm<2;gm++){
run(gm);
int best=(int)lo[1];
printf("gm=%d: tok=%d logit=%.2f str=\"",gm,best,lo[0]);
fwrite(rb[best],1,rl[best],stdout);printf("\"\n");}
